-- ---------------------------------------------
-- Source: 20260102_backfill_attendance_location_names.sql
-- ---------------------------------------------

-- Backfill Script: Update existing attendance events with location names
-- This script resolves addresses for historical attendance events that have coordinates but no location_name

-- First, let's see how many events need backfilling
SELECT COUNT(*) as events_needing_backfill
FROM public.attendance_events
WHERE latitude IS NOT NULL 
  AND longitude IS NOT NULL 
  AND location_name IS NULL;

-- Option 1: If you have the location_cache table populated, use it to backfill
UPDATE public.attendance_events ae
SET location_name = lc.address
FROM public.location_cache lc
WHERE ae.latitude IS NOT NULL
  AND ae.longitude IS NOT NULL
  AND ae.location_name IS NULL
  AND ae.latitude::numeric = lc.latitude
  AND ae.longitude::numeric = lc.longitude;

-- Option 2: If events are within a defined geofence location, use the location name
UPDATE public.attendance_events ae
SET location_name = COALESCE(l.name, l.address)
FROM public.locations l
WHERE ae.latitude IS NOT NULL
  AND ae.longitude IS NOT NULL
  AND ae.location_name IS NULL
  AND ae.location_id = l.id;

-- Verify the update
SELECT COUNT(*) as events_still_needing_backfill
FROM public.attendance_events
WHERE latitude IS NOT NULL 
  AND longitude IS NOT NULL 
  AND location_name IS NULL;


-- ---------------------------------------------
-- Source: 20260103_add_field_staff_holiday.sql
-- ---------------------------------------------

-- 1. Ensure 'office' and 'field' keys exist in attendance_settings
UPDATE public.settings
SET attendance_settings = jsonb_set(
    jsonb_set(
        COALESCE(attendance_settings, '{}'::jsonb),
        '{office}',
        COALESCE(attendance_settings->'office', '{}'::jsonb),
        true
    ),
    '{field}',
    COALESCE(attendance_settings->'field', '{}'::jsonb),
    true
);

-- 2. Add 3rd Saturday for Office Staff (if not already present)
UPDATE public.settings
SET attendance_settings = jsonb_set(
    attendance_settings,
    '{office,recurringHolidays}',
    COALESCE(attendance_settings->'office'->'recurringHolidays', '[]'::jsonb) || '[{"day": "Saturday", "n": 3, "type": "office"}]'::jsonb
)
WHERE NOT (attendance_settings->'office'->'recurringHolidays' @> '[{"day": "Saturday", "n": 3}]'::jsonb);

-- 3. Add 3rd Saturday for Field Staff (if not already present)
UPDATE public.settings
SET attendance_settings = jsonb_set(
    attendance_settings,
    '{field,recurringHolidays}',
    COALESCE(attendance_settings->'field'->'recurringHolidays', '[]'::jsonb) || '[{"day": "Saturday", "n": 3, "type": "field"}]'::jsonb
)
WHERE attendance_settings->'field'->'recurringHolidays' IS NULL 
   OR NOT (attendance_settings->'field'->'recurringHolidays' @> '[{"day": "Saturday", "n": 3}]'::jsonb);

-- Verify the update
SELECT 
    attendance_settings->'office'->'recurringHolidays' as office_rules,
    attendance_settings->'field'->'recurringHolidays' as field_rules
FROM public.settings LIMIT 1;


