-- ---------------------------------------------
-- Source: 20260220_fix_location_rls_roles.sql
-- ---------------------------------------------

-- Migration: Fix Location RLS for Managers
-- Date: 2026-02-20
-- Description: Broadens check_is_admin to include all management roles so they can store location data.

-- 1. Update check_is_admin to include all management roles
CREATE OR REPLACE FUNCTION public.check_is_admin()
RETURNS boolean AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM public.users 
    WHERE id = (select auth.uid()) 
    AND role_id IN ('admin', 'hr', 'super_admin', 'management', 'field_manager', 'hr_ops', 'ops_manager', 'developer', 'finance', 'site_manager')
  );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER STABLE;

-- 2. Ensure locations table policies allow these roles
DROP POLICY IF EXISTS "locations_insert_policy" ON public.locations;
DROP POLICY IF EXISTS "locations_update_policy" ON public.locations;
DROP POLICY IF EXISTS "locations_delete_policy" ON public.locations;

CREATE POLICY "locations_insert_policy" ON public.locations FOR INSERT WITH CHECK (public.check_is_admin());
CREATE POLICY "locations_update_policy" ON public.locations FOR UPDATE USING (public.check_is_admin());
CREATE POLICY "locations_delete_policy" ON public.locations FOR DELETE USING (public.check_is_admin());


-- ---------------------------------------------
-- Source: 20260221_cleanup_notification_uuids.sql
-- ---------------------------------------------

-- Migration to replace UUIDs with names in security notifications
DO $$
DECLARE
    notif_record RECORD;
    user_name TEXT;
BEGIN
    FOR notif_record IN 
        SELECT id, message, user_id, 
               (regexp_matches(message, '[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}', 'i'))[1] as found_uuid
        FROM public.notifications
        WHERE (type = 'security' OR message ILIKE '%violation%')
          AND message ~ '[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}'
    LOOP
        -- Find the name of the user whose UUID is in the message
        -- Note: the UUID in the message might NOT be the recipient (user_id), but the actor.
        SELECT name INTO user_name FROM public.users WHERE id = notif_record.found_uuid::uuid;
        
        IF user_name IS NOT NULL THEN
            UPDATE public.notifications
            SET message = replace(message, notif_record.found_uuid, user_name)
            WHERE id = notif_record.id;
        END IF;
    END LOOP;
END $$;


-- ---------------------------------------------
-- Source: 20260221_employee_scores.sql
-- ---------------------------------------------

-- Employee Scoring System: Create the employee_scores table
-- Run this migration in your Supabase SQL Editor

CREATE TABLE IF NOT EXISTS employee_scores (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  month DATE NOT NULL, -- First day of month, e.g. '2026-02-01'
  performance_score INTEGER NOT NULL DEFAULT 0 CHECK (performance_score >= 0 AND performance_score <= 100),
  attendance_score INTEGER NOT NULL DEFAULT 0 CHECK (attendance_score >= 0 AND attendance_score <= 100),
  response_score INTEGER NOT NULL DEFAULT 0 CHECK (response_score >= 0 AND response_score <= 100),
  overall_score INTEGER NOT NULL DEFAULT 0 CHECK (overall_score >= 0 AND overall_score <= 100),
  role_category TEXT NOT NULL DEFAULT 'office_staff' CHECK (role_category IN ('office_staff', 'field_staff', 'support')),
  calculated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  
  -- Ensure one score per user per month
  UNIQUE(user_id, month)
);

-- Index for fast lookups
CREATE INDEX IF NOT EXISTS idx_employee_scores_user_month ON employee_scores(user_id, month DESC);

-- RLS Policies
ALTER TABLE employee_scores ENABLE ROW LEVEL SECURITY;

-- Users can read their own scores
CREATE POLICY "Users can view own scores"
  ON employee_scores FOR SELECT
  USING (auth.uid() = user_id);

-- Admins can read all scores
CREATE POLICY "Admins can view all scores"
  ON employee_scores FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM users WHERE id = auth.uid() AND role_id IN ('admin', 'management')
    )
  );

-- Service role / authenticated users can insert/update their own scores
CREATE POLICY "Users can upsert own scores"
  ON employee_scores FOR ALL
  USING (auth.uid() = user_id)
  WITH CHECK (auth.uid() = user_id);


