ADD COLUMN IF NOT EXISTS violation_details JSONB DEFAULT '{}'::jsonb,
ADD COLUMN IF NOT EXISTS severity TEXT DEFAULT 'Low';

-- 2. Enhance field_attendance_violations (Site/Travel)
-- Note: violation_type already exists in some scripts, but we ensure it's there and add others
ALTER TABLE public.field_attendance_violations 
ADD COLUMN IF NOT EXISTS violation_details JSONB DEFAULT '{}'::jsonb,
ADD COLUMN IF NOT EXISTS severity TEXT DEFAULT 'Low';

-- 3. Enhance notifications
ALTER TABLE public.notifications
ADD COLUMN IF NOT EXISTS severity TEXT DEFAULT 'Low',
ADD COLUMN IF NOT EXISTS metadata JSONB DEFAULT '{}'::jsonb;

-- 4. Update existing records (optional but good for consistency)
UPDATE public.attendance_violations SET severity = 'Low' WHERE severity IS NULL;
UPDATE public.field_attendance_violations SET severity = 'Low' WHERE severity IS NULL;
UPDATE public.notifications SET severity = 'Low' WHERE severity IS NULL;
UPDATE public.attendance_violations SET violation_details = '{}'::jsonb WHERE violation_details IS NULL;
UPDATE public.field_attendance_violations SET violation_details = '{}'::jsonb WHERE violation_details IS NULL;
UPDATE public.notifications SET metadata = '{}'::jsonb WHERE metadata IS NULL;


-- ---------------------------------------------
-- Source: 20260223071707_broadcast_notification.sql
-- ---------------------------------------------

-- Create an RPC to broadcast a notification to all users
CREATE OR REPLACE FUNCTION broadcast_notification(
  p_message text,
  p_type text,
  p_severity text,
  p_metadata jsonb,
  p_link_to text DEFAULT NULL
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  INSERT INTO notifications (user_id, message, type, severity, metadata, link_to)
  SELECT id, p_message, p_type, p_severity, p_metadata, p_link_to
  FROM users;
END;
$$;


-- ---------------------------------------------
-- Source: 20260223_fix_notification_metadata.sql
-- ---------------------------------------------

-- Migration: 20260223_fix_notification_metadata.sql
-- Goal: Ensure columns exist and backfill missing employeeName metadata for security notifications.

-- 1. Ensure columns exist (Self-healing in case previous migrations were skipped)
ALTER TABLE public.notifications ADD COLUMN IF NOT EXISTS severity TEXT DEFAULT 'Low';
ALTER TABLE public.notifications ADD COLUMN IF NOT EXISTS metadata JSONB DEFAULT '{}'::jsonb;

DO $$
DECLARE
    rec RECORD;
BEGIN
    -- 2. Iterate through all users to find notifications with their name in the message
    FOR rec IN (
        SELECT id, name FROM public.users
    ) LOOP
        -- Update notifications where the message contains the user's name
        -- and the metadata is missing the employeeName property
        UPDATE public.notifications
        SET metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object('employeeName', rec.name)
        WHERE (
            message ILIKE '%' || rec.name || '%'
        )
        AND (
            metadata IS NULL OR 
            NOT (metadata ? 'employeeName')
        )
        AND (
            type = 'security' OR
            message ILIKE '%Field attendance violation%' OR 
            message ILIKE '%URGENT:%'
        );
    END LOOP;

    -- 3. Ensure all 'security' notifications have some metadata if null
    UPDATE public.notifications
    SET metadata = '{}'::jsonb
    WHERE metadata IS NULL AND type = 'security';

END $$;


-- ---------------------------------------------
-- Source: 20260224_resolve_notification_names.sql
-- ---------------------------------------------

-- Migration: 20260224_resolve_notification_names.sql
-- Goal: Resolve employee names in existing notifications by updating message and metadata.

DO $$
DECLARE
    rec RECORD;
    user_rec RECORD;
    updated_message TEXT;
    updated_metadata JSONB;
BEGIN
    -- 1. Loop through all security notifications
    FOR rec IN (
        SELECT id, message, metadata FROM public.notifications 
        WHERE type = 'security' OR message ILIKE '%Field attendance violation%'
    ) LOOP
        updated_message := rec.message;
        updated_metadata := rec.metadata;

        -- 2. Try to find a user name match
        -- We iterate through users to find if their ID is in the message or metadata
        FOR user_rec IN (SELECT id, name FROM public.users) LOOP
            -- Check if user ID is in the message or already in metadata
            IF updated_message ILIKE '%' || user_rec.id::text || '%' OR 
               (updated_metadata->>'employeeId')::text = user_rec.id::text THEN
                
                -- Update message: Replace UUID with Name
                updated_message := REPLACE(updated_message, user_rec.id::text, user_rec.name);
                
                -- Update metadata: Set employeeName
                updated_metadata := jsonb_set(
                    COALESCE(updated_metadata, '{}'::jsonb),
                    '{employeeName}',
                    to_jsonb(user_rec.name)
                );
                
                -- Also ensure employeeId is set if we found it in the message
                IF updated_metadata->>'employeeId' IS NULL THEN
                    updated_metadata := jsonb_set(
                        updated_metadata,
                        '{employeeId}',
                        to_jsonb(user_rec.id::text)
                    );
                END IF;
            END IF;
        END LOOP;

        -- 3. Final cleanup for wording
        updated_message := REPLACE(updated_message, 'escalated to HR/Admin', 'escalated to Admin');
        
        -- 4. Update the notification record if anything changed
        IF updated_message <> rec.message OR updated_metadata <> rec.metadata THEN
            UPDATE public.notifications
            SET 
                message = updated_message,
                metadata = updated_metadata
            WHERE id = rec.id;
        END IF;

    END LOOP;

    -- 5. Generic cleanup for any remaining "HR/Admin"
    UPDATE public.notifications
    SET message = REPLACE(message, 'escalated to HR/Admin', 'escalated to Admin')
    WHERE message ILIKE '%HR/Admin%';

END $$;


