-- Source: 20260227_fix_employee_scores_rls.sql
-- ---------------------------------------------

-- Fix RLS policies for employee_scores table
-- Allows authenticated users to read all scores, and insert/update their own scores

-- Enable RLS if not already enabled
ALTER TABLE IF EXISTS employee_scores ENABLE ROW LEVEL SECURITY;

-- Drop existing restrictive policies (if any)
DROP POLICY IF EXISTS "Users can read all employee scores" ON employee_scores;
DROP POLICY IF EXISTS "Users can insert scores" ON employee_scores;
DROP POLICY IF EXISTS "Users can update scores" ON employee_scores;
DROP POLICY IF EXISTS "Users can insert own scores" ON employee_scores;
DROP POLICY IF EXISTS "Users can update own scores" ON employee_scores;
DROP POLICY IF EXISTS "Allow all operations on employee_scores" ON employee_scores;

-- Allow all authenticated users to read all scores (needed for Top Performers)
CREATE POLICY "Users can read all employee scores"
  ON employee_scores FOR SELECT
  TO authenticated
  USING (true);

-- Allow authenticated users to insert scores (scoring runs client-side)
CREATE POLICY "Users can insert scores"
  ON employee_scores FOR INSERT
  TO authenticated
  WITH CHECK (true);

-- Allow authenticated users to update scores (upsert needs this)
CREATE POLICY "Users can update scores"
  ON employee_scores FOR UPDATE
  TO authenticated
  USING (true)
  WITH CHECK (true);


-- ---------------------------------------------
-- Source: 20260227_fix_ot_trigger_role_column.sql
-- ---------------------------------------------

-- Migration: 20260227_fix_ot_trigger_role_column.sql
-- Description: Fixes the process_ot_after_checkout trigger function which references
--              non-existent column u.role instead of u.role_id on the users table.
--              This was causing a 400 Bad Request (42703: column u.role does not exist)
--              on every attendance event INSERT (punch-in/out).

CREATE OR REPLACE FUNCTION public.process_ot_after_checkout()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    prev_check_in timestamptz;
    work_duration_min int;
    work_duration_hours numeric;
    user_role_name text;
    staff_cat text;
    std_hours_max numeric := 8; -- Default fallback
    daily_ot numeric := 0;
    settings_jsonb jsonb;
    u_manager_id uuid;
    u_name text;
BEGIN
    -- Only process punch-outs
    IF NEW.type != 'punch-out' THEN
        RETURN NEW;
    END IF;

    -- 1. Find the corresponding punch-in
    SELECT timestamp INTO prev_check_in
    FROM public.attendance_events
    WHERE user_id = NEW.user_id
    AND type = 'punch-in'
    AND timestamp < NEW.timestamp
    ORDER BY timestamp DESC
    LIMIT 1;

    IF prev_check_in IS NULL THEN
        RETURN NEW;
    END IF;

    -- 2. Calculate worked hours
    work_duration_min := EXTRACT(EPOCH FROM (NEW.timestamp - prev_check_in)) / 60;
    work_duration_hours := work_duration_min / 60.0;

    -- 3. Get User Role and Settings (FIX: use role_id instead of role)
    SELECT u.role_id, u.reporting_manager_id, u.name 
    INTO user_role_name, u_manager_id, u_name
    FROM public.users u WHERE u.id = NEW.user_id;

    -- Determine Staff Category
    staff_cat := 'field'; -- Default
    IF user_role_name IN (
        'admin', 'hr', 'finance', 'developer', 'management', 'office_staff', 
        'back_office_staff', 'bd', 'operation_manager', 'field_staff',
        'finance_manager', 'hr_ops', 'business developer', 'unverified',
        'operation manager', 'field staff', 'finance manager', 'hr ops'
    ) THEN
        staff_cat := 'office';
    ELSIF user_role_name IN ('site_manager', 'site_supervisor', 'site manager', 'site supervisor') THEN
        staff_cat := 'site';
    END IF;

    -- 4. Get Dynamic Threshold
    SELECT attendance_settings INTO settings_jsonb FROM public.settings WHERE id = 'singleton';
    
    IF settings_jsonb ? staff_cat AND (settings_jsonb->staff_cat) ? 'dailyWorkingHours' THEN
        std_hours_max := (settings_jsonb->staff_cat->'dailyWorkingHours'->>'max')::numeric;
    END IF;

    -- 5. Calculate OT
    IF work_duration_hours > std_hours_max THEN
        daily_ot := work_duration_hours - std_hours_max;
        
        -- 6. Update User OT Balances
        UPDATE public.users 
        SET 
            ot_hours_bank = ot_hours_bank + daily_ot,
            monthly_ot_hours = monthly_ot_hours + daily_ot
        WHERE id = NEW.user_id;

        -- 7. Check for Comp Off Conversion
        DECLARE
            curr_bank numeric;
            compoff_count int;
        BEGIN
            SELECT ot_hours_bank INTO curr_bank FROM public.users WHERE id = NEW.user_id;
            
            IF curr_bank >= 8 THEN
                compoff_count := floor(curr_bank / 8)::int;
                
                -- Create Comp Off Logs
                FOR i IN 1..compoff_count LOOP
                    INSERT INTO public.comp_off_logs (
                        user_id, user_name, date_earned, reason, status, granted_by_name
                    ) VALUES (
                        NEW.user_id, u_name, CURRENT_DATE, 'Automatic OT conversion', 'earned', 'System'
                    );
                END LOOP;

                -- Deduct from bank
                UPDATE public.users 
                SET ot_hours_bank = ot_hours_bank - (compoff_count * 8)
                WHERE id = NEW.user_id;

                -- 8. Notify User
                INSERT INTO public.notifications (user_id, message, type, link_to)
                VALUES (
                    NEW.user_id, 
                    format('Congratulations! You earned %s Comp Off(s) from accumulated Overtime.', compoff_count),
                    'success', 
                    '/leaves'
                );

                -- 9. Notify Manager
                IF u_manager_id IS NOT NULL THEN
                    INSERT INTO public.notifications (user_id, message, type, link_to)
                    VALUES (
                        u_manager_id,
                        format('%s has earned %s Comp Off(s) via automatic OT conversion.', u_name, compoff_count),
                        'info',
                        '/team'
                    );
                END IF;
            END IF;
        END;
    END IF;

    RETURN NEW;
END;
$$;


-- ---------------------------------------------
-- Source: 20260227_fix_scores_users_rls.sql
-- ---------------------------------------------

-- Create a database view or RPC that securely bypasses RLS for the users table when fetching scores

-- Safest approach: create a view that joins the tables and applies a policy, or a security-definer function
CREATE OR REPLACE FUNCTION get_employee_scores_with_users(p_month DATE)
RETURNS TABLE (
  score_id UUID,
  user_id UUID,
  user_name TEXT,
  user_role TEXT,
  user_photo_url TEXT,
  performance_score INTEGER,
  attendance_score INTEGER,
  response_score INTEGER,
  overall_score INTEGER,
  tiebreaker_score INTEGER,
  role_category TEXT,
  calculated_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT 
    s.id as score_id,
    s.user_id,
    u.name as user_name,
    u.role_id as user_role,
    u.photo_url as user_photo_url,
    s.performance_score,
    s.attendance_score,
    s.response_score,
    s.overall_score,
    COALESCE(s.tiebreaker_score, 0) as tiebreaker_score,
    s.role_category,
    s.calculated_at,
    s.created_at
  FROM employee_scores s
  JOIN users u ON u.id = s.user_id
  WHERE s.month = p_month
  ORDER BY s.overall_score DESC, s.tiebreaker_score DESC;
$$;


-- ---------------------------------------------
-- Source: 20260227_rename_event_types.sql
-- ---------------------------------------------

-- Migration: 20260227_rename_event_types.sql
-- Description: Renames check-in/check-out to punch-in/punch-out across the database.

-- 1. Update existing records in attendance_events
-- We handle both hyphenated and underscored versions for robustness
UPDATE public.attendance_events 
SET type = 'punch-in' 
WHERE type IN ('check-in', 'check_in');

UPDATE public.attendance_events 
SET type = 'punch-out' 
WHERE type IN ('check-out', 'check_out');

-- 2. Update OT Processing Function
-- This function was using 'check_out' and 'check_in' previously
CREATE OR REPLACE FUNCTION public.process_ot_after_checkout()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    prev_check_in timestamptz;
    work_duration_min int;
    work_duration_hours numeric;
    user_role_name text;
    staff_cat text;
    std_hours_max numeric := 8; -- Default fallback
    daily_ot numeric := 0;
    settings_jsonb jsonb;
    u_manager_id uuid;
    u_name text;
BEGIN
    -- Only process punch-outs
    IF NEW.type != 'punch-out' THEN
        RETURN NEW;
    END IF;

    -- 1. Find the corresponding punch-in
    SELECT timestamp INTO prev_check_in
    FROM public.attendance_events
    WHERE user_id = NEW.user_id
    AND type = 'punch-in'
    AND timestamp < NEW.timestamp
    ORDER BY timestamp DESC
    LIMIT 1;

    IF prev_check_in IS NULL THEN
        RETURN NEW;
    END IF;

    -- 2. Calculate worked hours
    work_duration_min := EXTRACT(EPOCH FROM (NEW.timestamp - prev_check_in)) / 60;
    work_duration_hours := work_duration_min / 60.0;

    -- 3. Get User Role and Settings
    SELECT u.role, u.reporting_manager_id, u.name 
    INTO user_role_name, u_manager_id, u_name
    FROM public.users u WHERE u.id = NEW.user_id;

    -- Determine Staff Category
    staff_cat := 'field'; -- Default
    IF user_role_name IN (
        'admin', 'hr', 'finance', 'developer', 'management', 'office_staff', 
        'back_office_staff', 'bd', 'operation_manager', 'field_staff',
        'finance_manager', 'hr_ops', 'business developer', 'unverified',
        'operation manager', 'field staff', 'finance manager', 'hr ops'
    ) THEN
        staff_cat := 'office';
    ELSIF user_role_name IN ('site_manager', 'site_supervisor', 'site manager', 'site supervisor') THEN
        staff_cat := 'site';
    END IF;

    -- 4. Get Dynamic Threshold
    SELECT attendance_settings INTO settings_jsonb FROM public.settings WHERE id = 'singleton';
    
    IF settings_jsonb ? staff_cat AND (settings_jsonb->staff_cat) ? 'dailyWorkingHours' THEN
        std_hours_max := (settings_jsonb->staff_cat->'dailyWorkingHours'->>'max')::numeric;
    END IF;

    -- 5. Calculate OT
    IF work_duration_hours > std_hours_max THEN
        daily_ot := work_duration_hours - std_hours_max;
        
        -- 6. Update User OT Balances
        UPDATE public.users 
        SET 
            ot_hours_bank = ot_hours_bank + daily_ot,
            monthly_ot_hours = monthly_ot_hours + daily_ot
        WHERE id = NEW.user_id;

        -- 7. Check for Comp Off Conversion
        DECLARE
            curr_bank numeric;
            compoff_count int;
        BEGIN
            SELECT ot_hours_bank INTO curr_bank FROM public.users WHERE id = NEW.user_id;
            
            IF curr_bank >= 8 THEN
                compoff_count := floor(curr_bank / 8)::int;
                
                -- Create Comp Off Logs
                FOR i IN 1..compoff_count LOOP
                    INSERT INTO public.comp_off_logs (
                        user_id, user_name, date_earned, reason, status, granted_by_name
                    ) VALUES (
                        NEW.user_id, u_name, CURRENT_DATE, 'Automatic OT conversion', 'earned', 'System'
                    );
                END LOOP;

                -- Deduct from bank
                UPDATE public.users 
                SET ot_hours_bank = ot_hours_bank - (compoff_count * 8)
                WHERE id = NEW.user_id;

                -- 8. Notify User
                INSERT INTO public.notifications (user_id, message, type, link_to)
                VALUES (
                    NEW.user_id, 
                    format('Congratulations! You earned %s Comp Off(s) from accumulated Overtime.', compoff_count),
                    'success', 
                    '/leaves'
                );

                -- 9. Notify Manager
                IF u_manager_id IS NOT NULL THEN
                    INSERT INTO public.notifications (user_id, message, type, link_to)
                    VALUES (
                        u_manager_id,
                        format('%s has earned %s Comp Off(s) via automatic OT conversion.', u_name, compoff_count),
                        'info',
                        '/team'
                    );
                END IF;
            END IF;
        END;
    END IF;

    RETURN NEW;
END;
$$;

-- 3. Update Audit Logs (Optional but recommended for consistency)
UPDATE public.attendance_audit_logs 
SET details = jsonb_set(
    details, 
    '{message}', 
    to_jsonb(replace(replace(details->>'message', 'check-in', 'punch-in'), 'check-out', 'punch-out'))
)
WHERE details ? 'message' 
AND (details->>'message' LIKE '%check-in%' OR details->>'message' LIKE '%check-out%');


-- ---------------------------------------------
-- Source: 20260302_add_revision_tracking.sql
-- ---------------------------------------------

-- Migration: Add revision tracking to tracker tables
-- Description: Creates revision history tables and adds revision_count to main tables.

-- 1. Add revision_count to main tables
ALTER TABLE public.site_invoice_tracker 
ADD COLUMN IF NOT EXISTS revision_count INTEGER DEFAULT 0;

ALTER TABLE public.site_finance_tracker 
ADD COLUMN IF NOT EXISTS revision_count INTEGER DEFAULT 0;

-- 2. Create site_invoice_revisions table
CREATE TABLE IF NOT EXISTS public.site_invoice_revisions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    record_id UUID NOT NULL REFERENCES public.site_invoice_tracker(id) ON DELETE CASCADE,
    revised_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    revised_by_name TEXT,
    revised_at TIMESTAMPTZ DEFAULT NOW(),
    diff JSONB NOT NULL, -- Stores { field: { old: val, new: val } }
    revision_number INTEGER NOT NULL
);

-- 3. Create site_finance_revisions table
CREATE TABLE IF NOT EXISTS public.site_finance_revisions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    record_id UUID NOT NULL REFERENCES public.site_finance_tracker(id) ON DELETE CASCADE,
    revised_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    revised_by_name TEXT,
    revised_at TIMESTAMPTZ DEFAULT NOW(),
    diff JSONB NOT NULL,
    revision_number INTEGER NOT NULL
);

-- 4. Enable RLS
ALTER TABLE public.site_invoice_revisions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.site_finance_revisions ENABLE ROW LEVEL SECURITY;

-- 5. RLS Policies (Basic access for authenticated users)
DROP POLICY IF EXISTS "Enable read access for all users" ON public.site_invoice_revisions;
CREATE POLICY "Enable read access for all users" ON public.site_invoice_revisions
    FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Enable insert for all users" ON public.site_invoice_revisions;
CREATE POLICY "Enable insert for all users" ON public.site_invoice_revisions
    FOR INSERT TO authenticated WITH CHECK (true);

DROP POLICY IF EXISTS "Enable read access for all users" ON public.site_finance_revisions;
CREATE POLICY "Enable read access for all users" ON public.site_finance_revisions
    FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Enable insert for all users" ON public.site_finance_revisions;
CREATE POLICY "Enable insert for all users" ON public.site_finance_revisions
    FOR INSERT TO authenticated WITH CHECK (true);

-- 6. Indexes for performance
CREATE INDEX IF NOT EXISTS idx_site_invoice_revisions_record_id ON public.site_invoice_revisions(record_id);
CREATE INDEX IF NOT EXISTS idx_site_finance_revisions_record_id ON public.site_finance_revisions(record_id);


-- ---------------------------------------------
-- Source: 20260302_communication_logs.sql
-- ---------------------------------------------


-- Migration to add communication_logs table for tracking in-app interactions

CREATE TABLE IF NOT EXISTS public.communication_logs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    sender_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
    receiver_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
    type TEXT NOT NULL CHECK (type IN ('call', 'sms', 'whatsapp', 'ping')),
    metadata JSONB DEFAULT '{}'::jsonb,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL
);

-- Enable RLS
ALTER TABLE public.communication_logs ENABLE ROW LEVEL SECURITY;

-- Policies
CREATE POLICY "Users can view communication logs they are part of" 
ON public.communication_logs FOR SELECT 
USING (auth.uid() = sender_id OR auth.uid() = receiver_id);

CREATE POLICY "Users can insert their own communication logs" 
ON public.communication_logs FOR INSERT 
WITH CHECK (auth.uid() = sender_id);

-- Admin/Management can view all logs
CREATE POLICY "Managers can view all communication logs" 
ON public.communication_logs FOR SELECT 
USING (
  EXISTS (
    SELECT 1 FROM public.users 
    WHERE id = auth.uid() 
    AND role_id IN ('admin', 'management', 'site_manager')
  )
);


-- ---------------------------------------------
-- Source: 20260302_fix_created_by_references.sql
-- ---------------------------------------------

-- Fix foreign key references for created_by column in tracker tables
-- These should reference public.users(id) to allow joins with reporting_manager_id etc.
-- Date: 2026-03-02

DO $$ 
BEGIN
    -- 1. Fix site_invoice_tracker
    -- We need to drop the constraint if it exists. PostgREST usually names it [table]_[column]_fkey
    IF EXISTS (SELECT 1 FROM information_schema.table_constraints WHERE table_name = 'site_invoice_tracker' AND constraint_name = 'site_invoice_tracker_created_by_fkey') THEN
        ALTER TABLE public.site_invoice_tracker DROP CONSTRAINT site_invoice_tracker_created_by_fkey;
    END IF;
    
    ALTER TABLE public.site_invoice_tracker 
    ADD CONSTRAINT site_invoice_tracker_created_by_fkey 
    FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;


    -- 2. Fix site_invoice_defaults
    IF EXISTS (SELECT 1 FROM information_schema.table_constraints WHERE table_name = 'site_invoice_defaults' AND constraint_name = 'site_invoice_defaults_created_by_fkey') THEN
        ALTER TABLE public.site_invoice_defaults DROP CONSTRAINT site_invoice_defaults_created_by_fkey;
    END IF;
    
    ALTER TABLE public.site_invoice_defaults 
    ADD CONSTRAINT site_invoice_defaults_created_by_fkey 
    FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;


    -- 3. Fix site_finance_tracker
    IF EXISTS (SELECT 1 FROM information_schema.table_constraints WHERE table_name = 'site_finance_tracker' AND constraint_name = 'site_finance_tracker_created_by_fkey') THEN
        ALTER TABLE public.site_finance_tracker DROP CONSTRAINT site_finance_tracker_created_by_fkey;
    END IF;
    
    ALTER TABLE public.site_finance_tracker 
    ADD CONSTRAINT site_finance_tracker_created_by_fkey 
    FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;

END $$;


